    private func performPasswordReset(newPassword: String) {
        resetButton.isEnabled = false
        activityIndicator.startAnimating()
        resetButton.setTitle("", for: .normal)
        
        guard let url = URL(string: "https://myapp.com/api/reset-password") else {
            handleResetError()
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let body: [String: String] = [
            "token": token,
            "newPassword": newPassword
        ]
        
        request.httpBody = try? JSONSerialization.data(withJSONObject: body)
        
        URLSession.shared.dataTask(with: request) { [weak self] data, response, error in
            DispatchQueue.main.async {
                self?.resetButton.isEnabled = true
                self?.activityIndicator.stopAnimating()
                self?.resetButton.setTitle("Reset Password", for: .normal)
                
                if let error = error {
                    self?.showAlert(title: "Error", message: "Network error: \(error.localizedDescription)")
                    return
                }
                
                guard let httpResponse = response as? HTTPURLResponse else {
                    self?.showAlert(title: "Error", message: "Invalid response from server.")
                    return
                }
                
                if httpResponse.statusCode == 200 {
                    self?.handleResetSuccess()
                } else {
                    var message = "Failed to reset password. Please try again."
                    if let data = data,
                       let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
                       let errorMessage = json["message"] as? String {
                        message = errorMessage
                    }
                    self?.showAlert(title: "Error", message: message)
                }
            }
        }.resume()
